fillColor:
{{
  (() => {
    const total = OperacionDia.datosFiltrados().filter(
      ot => ot.actividad_programada === "Recoleccion con cliente"
    ).length || 1;

    const completadas = OperacionDia.datosFiltrados().filter(
      ot => ot.actividad_programada === "Recoleccion con cliente" &&
            ot.estatus_ot === "Completada"
    ).length;

    const pct = (completadas / total) * 100;

    if (pct < 5) return "#16a34a"; // verde
    if (pct >= 5 && pct < 25) return "#eab308"; // amarillo
    if (pct >= 25 && pct < 50) return "#fb923c"; // naranja
    return "#dc2626"; // rojo
  })()
}}
